- Failing to release a mutex causes a deadlock, freezing all waiting threads.

```javascript
const { Mutex } = require('async-mutex');

const mutex = new Mutex();

let counter = 0;

async function increment() {
  const release = await mutex.acquire();
  try {

    counter++; // only one caller here at a time
  } finally {
    release();
  }
}
